}

// ── Article card ───────────────────────────────────────────────────────────────

function ArticleCard({ book, onDone }: { book: Book; onDone: (book: Book) => void }) {
  const [loading, setLoading] = useState(false)

  async function handleDone() {
    setLoading(true)
